/** UsptCnsltHistDao.insert */
insert into uspt_cnslt_hist (
	   hist_id
	 , extrc_mfcmm_id
	 , talk_dt
	 , lsn_result_cd
	 , cnslt_cn
	 , creator_id
	 , created_dt
) values (
	   #{histId}
	 , #{extrcMfcmmId}
	 , #{talkDt}
	 , #{lsnResultCd}
	 , #{cnsltCn}
	 , #{creatorId}
	 , #{createdDt}
)

mapper.delete:
/** UsptCnsltHistDao.delete */
delete
  from uspt_cnslt_hist
 where hist_id = #{histId}
